diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 86de89595957..459f77a74c01 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -28,7 +28,7 @@
 #include "llvm/IR/Function.h"
 #include "llvm/IR/IRBuilder.h"
 #include "llvm/IR/InstrTypes.h"
-#include "llvm/IR/Instructions.h"
+#include "llvm/IR/Instructions.h"\n#include "llvm/IR/ConstantRange.h"
 #include "llvm/IR/Module.h"
 #include "llvm/IR/PatternMatch.h"
 #include "llvm/IR/Verifier.h"
@@ -270,10 +270,14 @@ class ConstraintInfo {
   ConstraintSystem SignedCS;

   const DataLayout &DL;
+  
+  /// Number of initial constraints added from range attributes to signed system.
+  unsigned NumSignedRangeConstraints = 0;

 public:
   ConstraintInfo(const DataLayout &DL, ArrayRef<Value *> FunctionArgs)
-      : UnsignedCS(FunctionArgs), SignedCS(FunctionArgs), DL(DL) {
+      : UnsignedCS(FunctionArgs), SignedCS(FunctionArgs), DL(DL),
+        NumSignedRangeConstraints(0) {
     auto &Value2Index = getValue2Index(false);
     // Add Arg > -1 constraints to unsigned system for all function arguments.
     for (Value *Arg : FunctionArgs) {
@@ -282,6 +286,27 @@ public:
       VarPos.Coefficients[Value2Index[Arg]] = -1;
       UnsignedCS.addVariableRow(VarPos.Coefficients);
     }
+    // Add constraints from range attributes for signed system.
+    auto &SignedValue2Index = getValue2Index(true);
+    for (Value *Arg : FunctionArgs) {
+      if (auto *A = dyn_cast<Argument>(Arg)) {
+        if (std::optional<ConstantRange> Range = A->getRange()) {
+          // If the range lower bound is non-negative, add Arg >= lower to signed system.
+          if (Range->getLower().isNonNegative()) {
+            int64_t Lower = Range->getLower().getSExtValue();
+            // Constraint: Arg >= Lower  =>  0 >= -Arg + Lower
+            // Coefficients: [Lower, 0, ..., -1, ...] where -1 is at Arg's index
+            ConstraintTy RangeConstraint(
+                SmallVector<int64_t, 8>(SignedValue2Index.size() + 1, 0),
+                true, false, false);
+            RangeConstraint.Coefficients[0] = Lower;
+            RangeConstraint.Coefficients[SignedValue2Index[Arg]] = -1;
+            SignedCS.addVariableRow(RangeConstraint.Coefficients);
+            NumSignedRangeConstraints++;
+          }
+        }
+      }
+    }
   }

   DenseMap<Value *, unsigned> &getValue2Index(bool Signed) {
@@ -291,6 +316,8 @@ public:
     return Signed ? SignedCS.getValue2Index() : UnsignedCS.getValue2Index();
   }

+  unsigned getNumSignedRangeConstraints() const { return NumSignedRangeConstraints; }
+
   ConstraintSystem &getCS(bool Signed) {
     return Signed ? SignedCS : UnsignedCS;
   }
@@ -527,6 +554,14 @@ static Decomposition decompose(Value *V,
     if (match(V, m_NSWAdd(m_Value(Op0), m_Value(Op1))))
       return MergeResults(Op0, Op1, IsSigned);

+    if (match(V, m_NSWSub(m_Value(Op0), m_Value(Op1)))) {
+      auto ResA = decompose(Op0, Preconditions, IsSigned, DL);
+      auto ResB = decompose(Op1, Preconditions, IsSigned, DL);
+      ResA.sub(ResB);
+      return ResA;
+    }
+
+
     ConstantInt *CI;
     if (match(V, m_NSWMul(m_Value(Op0), m_ConstantInt(CI))) && canUseSExt(CI)) {
       auto Result = decompose(Op0, Preconditions, IsSigned, DL);
@@ -1901,7 +1936,7 @@ static bool eliminateConstraints(Function &F, DominatorTree &DT, LoopInfo &LI,
   assert(Info.getCS(false).size() - FunctionArgs.size() ==
              DFSInStack.size() - SignedEntries &&
          "updates to CS and DFSInStack are out of sync");
-  assert(Info.getCS(true).size() == SignedEntries &&
+  assert(Info.getCS(true).size() - Info.getNumSignedRangeConstraints() == SignedEntries &&
          "updates to CS and DFSInStack are out of sync");
 #endif

