  1377 | static std::optional<bool> checkCondition(CmpInst::Predicate Pred, Value *A,
  1378 |                                           Value *B, Instruction *CheckInst,
  1379 |                                           ConstraintInfo &Info) {
  1380 |   LLVM_DEBUG(dbgs() << "Checking " << *CheckInst << "\n");
  1381 | 
  1382 |   auto R = Info.getConstraintForSolving(Pred, A, B);
  1383 |   if (R.empty() || !R.isValid(Info)){
  1384 |     LLVM_DEBUG(dbgs() << "   failed to decompose condition\n");
  1385 |     return std::nullopt;
  1386 |   }
  1387 | 
  1388 |   auto &CSToUse = Info.getCS(R.IsSigned);
  1389 | 
  1390 |   // If there was extra information collected during decomposition, apply
  1391 |   // it now and remove it immediately once we are done with reasoning
  1392 |   // about the constraint.
  1393 |   for (auto &Row : R.ExtraInfo)
  1394 |     CSToUse.addVariableRow(Row);
  1395 |   auto InfoRestorer = make_scope_exit([&]() {
  1396 |     for (unsigned I = 0; I < R.ExtraInfo.size(); ++I)
  1397 |       CSToUse.popLastConstraint();
  1398 |   });
  1399 | 
  1400 |   if (auto ImpliedCondition = R.isImpliedBy(CSToUse)) {
  1401 |     if (!DebugCounter::shouldExecute(EliminatedCounter))
  1402 |       return std::nullopt;
  1403 | 
  1404 |     LLVM_DEBUG({
  1405 |       dbgs() << "Condition ";
  1406 |       dumpUnpackedICmp(
  1407 |           dbgs(), *ImpliedCondition ? Pred : CmpInst::getInversePredicate(Pred),
  1408 |           A, B);
  1409 |       dbgs() << " implied by dominating constraints\n";
  1410 |       CSToUse.dump();
  1411 |     });
  1412 |     return ImpliedCondition;
  1413 |   }
  1414 | 
  1415 |   return std::nullopt;
  1416 | }
