  1418 | static bool checkAndReplaceCondition(
  1419 |     CmpInst *Cmp, ConstraintInfo &Info, unsigned NumIn, unsigned NumOut,
  1420 |     Instruction *ContextInst, Module *ReproducerModule,
  1421 |     ArrayRef<ReproducerEntry> ReproducerCondStack, DominatorTree &DT,
  1422 |     SmallVectorImpl<Instruction *> &ToRemove) {
  1423 |   auto ReplaceCmpWithConstant = [&](CmpInst *Cmp, bool IsTrue) {
  1424 |     generateReproducer(Cmp, ReproducerModule, ReproducerCondStack, Info, DT);
  1425 |     Constant *ConstantC = ConstantInt::getBool(
  1426 |         CmpInst::makeCmpResultType(Cmp->getType()), IsTrue);
  1427 |     Cmp->replaceUsesWithIf(ConstantC, [&DT, NumIn, NumOut,
  1428 |                                        ContextInst](Use &U) {
  1429 |       auto *UserI = getContextInstForUse(U);
  1430 |       auto *DTN = DT.getNode(UserI->getParent());
  1431 |       if (!DTN || DTN->getDFSNumIn() < NumIn || DTN->getDFSNumOut() > NumOut)
  1432 |         return false;
  1433 |       if (UserI->getParent() == ContextInst->getParent() &&
  1434 |           UserI->comesBefore(ContextInst))
  1435 |         return false;
