  1437 |       // Conditions in an assume trivially simplify to true. Skip uses
  1438 |       // in assume calls to not destroy the available information.
  1439 |       auto *II = dyn_cast<IntrinsicInst>(U.getUser());
  1440 |       return !II || II->getIntrinsicID() != Intrinsic::assume;
  1441 |     });
  1442 |     NumCondsRemoved++;
  1443 |     if (Cmp->use_empty())
  1444 |       ToRemove.push_back(Cmp);
  1445 |     return true;
  1446 |   };
