  1475 | static bool checkAndReplaceCmp(CmpIntrinsic *I, ConstraintInfo &Info,
  1476 |                                SmallVectorImpl<Instruction *> &ToRemove) {
  1477 |   Value *LHS = I->getOperand(0);
  1478 |   Value *RHS = I->getOperand(1);
  1479 |   if (checkCondition(I->getGTPredicate(), LHS, RHS, I, Info).value_or(false)) {
  1480 |     I->replaceAllUsesWith(ConstantInt::get(I->getType(), 1));
  1481 |     ToRemove.push_back(I);
  1482 |     return true;
  1483 |   }
  1484 |   if (checkCondition(I->getLTPredicate(), LHS, RHS, I, Info).value_or(false)) {
  1485 |     I->replaceAllUsesWith(ConstantInt::getSigned(I->getType(), -1));
  1486 |     ToRemove.push_back(I);
  1487 |     return true;
  1488 |   }
  1489 |   if (checkCondition(ICmpInst::ICMP_EQ, LHS, RHS, I, Info).value_or(false)) {
  1490 |     I->replaceAllUsesWith(ConstantInt::get(I->getType(), 0));
  1491 |     ToRemove.push_back(I);
  1492 |     return true;
  1493 |   }
  1494 |   return false;
  1495 | }
