  1497 | static void
  1498 | removeEntryFromStack(const StackEntry &E, ConstraintInfo &Info,
  1499 |                      Module *ReproducerModule,
  1500 |                      SmallVectorImpl<ReproducerEntry> &ReproducerCondStack,
  1501 |                      SmallVectorImpl<StackEntry> &DFSInStack) {
  1502 |   Info.popLastConstraint(E.IsSigned);
  1503 |   // Remove variables in the system that went out of scope.
  1504 |   auto &Mapping = Info.getValue2Index(E.IsSigned);
  1505 |   for (Value *V : E.ValuesToRelease)
  1506 |     Mapping.erase(V);
  1507 |   Info.popLastNVariables(E.IsSigned, E.ValuesToRelease.size());
