  1513 | /// Check if either the first condition of an AND or OR is implied by the
  1514 | /// (negated in case of OR) second condition or vice versa.
  1515 | static bool checkOrAndOpImpliedByOther(
  1516 |     FactOrCheck &CB, ConstraintInfo &Info, Module *ReproducerModule,
  1517 |     SmallVectorImpl<ReproducerEntry> &ReproducerCondStack,
  1518 |     SmallVectorImpl<StackEntry> &DFSInStack) {
  1519 |   Instruction *JoinOp = CB.getContextInst();
  1520 |   CmpInst *CmpToCheck = cast<CmpInst>(CB.getInstructionToSimplify());
  1521 |   unsigned OtherOpIdx = JoinOp->getOperand(0) == CmpToCheck ? 1 : 0;
  1522 | 
  1523 |   // Don't try to simplify the first condition of a select by the second, as
  1524 |   // this may make the select more poisonous than the original one.
  1525 |   // TODO: check if the first operand may be poison.
  1526 |   if (OtherOpIdx != 0 && isa<SelectInst>(JoinOp))
  1527 |     return false;
  1528 | 
  1529 |   unsigned OldSize = DFSInStack.size();
  1530 |   auto InfoRestorer = make_scope_exit([&]() {
  1531 |     // Remove entries again.
  1532 |     while (OldSize < DFSInStack.size()) {
  1533 |       StackEntry E = DFSInStack.back();
  1534 |       removeEntryFromStack(E, Info, ReproducerModule, ReproducerCondStack,
  1535 |                            DFSInStack);
  1536 |     }
  1537 |   });
  1538 |   bool IsOr = match(JoinOp, m_LogicalOr());
  1539 |   SmallVector<Value *, 4> Worklist({JoinOp->getOperand(OtherOpIdx)});
  1540 |   // Do a traversal of the AND/OR tree to add facts from leaf compares.
  1541 |   while (!Worklist.empty()) {
  1542 |     Value *Val = Worklist.pop_back_val();
  1543 |     Value *LHS, *RHS;
  1544 |     CmpPredicate Pred;
  1545 |     if (match(Val, m_ICmp(Pred, m_Value(LHS), m_Value(RHS)))) {
  1546 |       // For OR, check if the negated condition implies CmpToCheck.
  1547 |       if (IsOr)
  1548 |         Pred = CmpInst::getInversePredicate(Pred);
  1549 |       // Optimistically add fact from the other compares in the AND/OR.
  1550 |       Info.addFact(Pred, LHS, RHS, CB.NumIn, CB.NumOut, DFSInStack);

